Create file src/storage.ts for VS Code extension time tracker:

import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import * as vscode from 'vscode';

export interface Segment {
  project: string;
  projectPath: string;
  start: string;  // ISO8601
  end: string;    // ISO8601
  duration_ms: number;
}

export function getLogFilePath(): string {
  const config = vscode.workspace.getConfiguration('vscodeTracker');
  const customPath = config.get<string>('logFilePath');
  if (customPath && customPath.length > 0) return customPath;
  const dir = path.join(os.homedir(), '.vscode-tracker');
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  return path.join(dir, 'logs.json');
}

export function loadSegments(): Segment[] {
  const filePath = getLogFilePath();
  if (!fs.existsSync(filePath)) return [];
  try {
    const raw = fs.readFileSync(filePath, 'utf-8');
    return JSON.parse(raw) as Segment[];
  } catch {
    return [];
  }
}

export function appendSegment(segment: Segment): void {
  const segments = loadSegments();
  segments.push(segment);
  fs.writeFileSync(getLogFilePath(), JSON.stringify(segments, null, 2));
}

export function exportCsv(): string {
  const segments = loadSegments();
  const lines = ['project,projectPath,start,end,duration_ms'];
  for (const s of segments) {
    lines.push(`"${s.project}","${s.projectPath}","${s.start}","${s.end}",${s.duration_ms}`);
  }
  return lines.join('\n');
}

Create file src/tracker.ts for VS Code extension time tracker:

import * as vscode from 'vscode';
import { Segment, appendSegment } from './storage';

export class TimeTracker implements vscode.Disposable {
  private sessionStart: Date | null = null;
  private currentProject: string = '';
  private currentPath: string = '';
  private lastActivity: Date = new Date();
  private idleTimer: NodeJS.Timeout | null = null;
  private disposables: vscode.Disposable[] = [];

  constructor() {
    this.disposables.push(
      vscode.window.onDidChangeWindowState(e => {
        if (e.focused) this.startSession();
        else this.endSession();
      }),
      vscode.window.onDidChangeActiveTextEditor(() => {
        this.lastActivity = new Date();
        if (!this.sessionStart) this.startSession();
      }),
      vscode.workspace.onDidChangeTextDocument(() => {
        this.lastActivity = new Date();
      }),
      vscode.workspace.onDidChangeWorkspaceFolders(() => {
        this.endSession();
        this.updateCurrentProject();
        this.startSession();
      })
    );
    this.updateCurrentProject();
    this.startSession();
    this.startIdleTimer();
  }

  private updateCurrentProject(): void {
    const folders = vscode.workspace.workspaceFolders;
    if (folders && folders.length > 0) {
      this.currentProject = folders[0].name;
      this.currentPath = folders[0].uri.fsPath;
    } else {
      this.currentProject = 'No workspace';
      this.currentPath = '';
    }
  }

  private startSession(): void {
    if (this.sessionStart) return;
    this.updateCurrentProject();
    this.sessionStart = new Date();
  }

  endSession(): void {
    if (!this.sessionStart) return;
    const end = new Date();
    const duration_ms = end.getTime() - this.sessionStart.getTime();
    if (duration_ms > 1000) {
      const segment: Segment = {
        project: this.currentProject,
        projectPath: this.currentPath,
        start: this.sessionStart.toISOString(),
        end: end.toISOString(),
        duration_ms
      };
      appendSegment(segment);
    }
    this.sessionStart = null;
  }

  private startIdleTimer(): void {
    this.idleTimer = setInterval(() => {
      const config = vscode.workspace.getConfiguration('vscodeTracker');
      const threshold = (config.get<number>('idleThresholdSeconds') ?? 120) * 1000;
      const idleMs = Date.now() - this.lastActivity.getTime();
      if (idleMs > threshold && this.sessionStart) {
        this.endSession();
      }
    }, 15000);
  }

  getSessionDuration(): number {
    if (!this.sessionStart) return 0;
    return Date.now() - this.sessionStart.getTime();
  }

  getCurrentProject(): string {
    return this.currentProject;
  }

  dispose(): void {
    this.endSession();
    if (this.idleTimer) clearInterval(this.idleTimer);
    this.disposables.forEach(d => d.dispose());
  }
}

Create file src/statusBar.ts for VS Code extension time tracker:

import * as vscode from 'vscode';
import { TimeTracker } from './tracker';

export class StatusBarManager implements vscode.Disposable {
  private statusBarItem: vscode.StatusBarItem;
  private updateTimer: NodeJS.Timeout;

  constructor(private tracker: TimeTracker) {
    this.statusBarItem = vscode.window.createStatusBarItem(
      vscode.StatusBarAlignment.Left,
      100
    );
    this.statusBarItem.command = 'vscodeTracker.showDashboard';
    this.statusBarItem.show();
    this.updateDisplay();
    this.updateTimer = setInterval(() => this.updateDisplay(), 60000);
  }

  private formatDuration(ms: number): string {
    const totalSeconds = Math.floor(ms / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
  }

  updateDisplay(): void {
    const project = this.tracker.getCurrentProject();
    const duration = this.tracker.getSessionDuration();
    const durationText = duration > 60000 ? `  ${this.formatDuration(duration)}` : '';
    this.statusBarItem.text = `$(clock) ${project}${durationText}`;
    this.statusBarItem.tooltip = `VS Code Time Tracker - Click to open dashboard`;
  }

  dispose(): void {
    clearInterval(this.updateTimer);
    this.statusBarItem.dispose();
  }
}

Create file src/dashboard.ts for VS Code extension time tracker:

import * as vscode from 'vscode';
import { loadSegments, Segment } from './storage';

interface ProjectStats {
  project: string;
  today_ms: number;
  week_ms: number;
  total_ms: number;
}

function aggregateStats(): ProjectStats[] {
  const segments = loadSegments();
  const now = new Date();
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const weekStart = new Date(todayStart);
  weekStart.setDate(weekStart.getDate() - weekStart.getDay());

  const map = new Map<string, ProjectStats>();

  for (const seg of segments) {
    const segDate = new Date(seg.start);
    if (!map.has(seg.project)) {
      map.set(seg.project, { project: seg.project, today_ms: 0, week_ms: 0, total_ms: 0 });
    }
    const stats = map.get(seg.project)!;
    stats.total_ms += seg.duration_ms;
    if (segDate >= weekStart) stats.week_ms += seg.duration_ms;
    if (segDate >= todayStart) stats.today_ms += seg.duration_ms;
  }

  return Array.from(map.values()).sort((a, b) => b.total_ms - a.total_ms);
}

function formatDuration(ms: number): string {
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  return `${h}h ${m}m ${s}s`;
}

export function generateDashboardHtml(panel: vscode.WebviewPanel): string {
  const stats = aggregateStats();
  const maxTotal = stats.length > 0 ? stats[0].total_ms : 1;

  const rows = stats.map(s => `
    <tr>
      <td>${s.project}</td>
      <td>${formatDuration(s.today_ms)}</td>
      <td>${formatDuration(s.week_ms)}</td>
      <td>
        <div class="bar-wrap">
          <div class="bar" style="width:${Math.round((s.total_ms/maxTotal)*100)}%"></div>
          <span>${formatDuration(s.total_ms)}</span>
        </div>
      </td>
    </tr>`).join('');

  return `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body { font-family: var(--vscode-font-family); color: var(--vscode-foreground); background: var(--vscode-editor-background); padding: 20px; }
  h1 { font-size: 1.4em; margin-bottom: 20px; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
  th, td { text-align: left; padding: 8px 12px; border-bottom: 1px solid var(--vscode-widget-border); }
  th { font-weight: bold; color: var(--vscode-descriptionForeground); }
  .bar-wrap { display: flex; align-items: center; gap: 8px; }
  .bar { height: 14px; background: var(--vscode-progressBar-background, #0e70c0); border-radius: 3px; min-width: 2px; }
  button { background: var(--vscode-button-background); color: var(--vscode-button-foreground); border: none; padding: 8px 16px; cursor: pointer; border-radius: 3px; }
  button:hover { background: var(--vscode-button-hoverBackground); }
</style>
</head>
<body>
<h1>$(clock) VS Code Time Tracker</h1>
<table>
  <thead><tr><th>Project</th><th>Today</th><th>This Week</th><th>Total</th></tr></thead>
  <tbody>${rows}</tbody>
</table>
<button onclick="exportCsv()">Export CSV</button>
<script>
  const vscode = acquireVsCodeApi();
  function exportCsv() { vscode.postMessage({ command: 'exportCsv' }); }
</script>
</body>
</html>`;
}

export function openDashboard(context: vscode.ExtensionContext): void {
  const panel = vscode.window.createWebviewPanel(
    'vscodeTracker',
    'Time Tracker Dashboard',
    vscode.ViewColumn.One,
    { enableScripts: true }
  );
  panel.webview.html = generateDashboardHtml(panel);
  panel.webview.onDidReceiveMessage(msg => {
    if (msg.command === 'exportCsv') {
      const { exportCsv, getLogFilePath } = require('./storage');
      const csvPath = getLogFilePath().replace('.json', '.csv');
      require('fs').writeFileSync(csvPath, exportCsv());
      vscode.window.showInformationMessage(`CSV exported to ${csvPath}`);
    }
  }, undefined, context.subscriptions);
}

Create file src/extension.ts as the entry point for the VS Code time tracker extension:

import * as vscode from 'vscode';
import * as fs from 'fs';
import * as path from 'path';
import { TimeTracker } from './tracker';
import { StatusBarManager } from './statusBar';
import { openDashboard } from './dashboard';
import { getLogFilePath, exportCsv, loadSegments } from './storage';

let tracker: TimeTracker;
let statusBar: StatusBarManager;

export function activate(context: vscode.ExtensionContext): void {
  tracker = new TimeTracker();
  statusBar = new StatusBarManager(tracker);

  context.subscriptions.push(
    tracker,
    statusBar,
    vscode.commands.registerCommand('vscodeTracker.showDashboard', () => {
      openDashboard(context);
    }),
    vscode.commands.registerCommand('vscodeTracker.resetToday', () => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const segments = loadSegments().filter(s => new Date(s.start) < today);
      fs.writeFileSync(getLogFilePath(), JSON.stringify(segments, null, 2));
      vscode.window.showInformationMessage('Today stats reset.');
    }),
    vscode.commands.registerCommand('vscodeTracker.exportCsv', () => {
      const csvPath = getLogFilePath().replace('.json', '.csv');
      fs.writeFileSync(csvPath, exportCsv());
      vscode.window.showInformationMessage(`Exported to ${csvPath}`);
    }),
    vscode.commands.registerCommand('vscodeTracker.openLog', () => {
      vscode.workspace.openTextDocument(getLogFilePath()).then(doc => {
        vscode.window.showTextDocument(doc);
      });
    })
  );

  vscode.window.showInformationMessage('VS Code Time Tracker active.');
}

export function deactivate(): void {
  if (tracker) tracker.dispose();
  if (statusBar) statusBar.dispose();
}
